import{_ as e,o as i,c as t,a0 as a}from"./chunks/framework.B3sz4m_N.js";const n=""+new URL("../report/agentic-techniques-05-medium-impact-gaps.png",import.meta.url).href,k=JSON.parse('{"title":"Medium-Impact Gaps","description":"Prompt maturity advancement, evaluation loops, self-improvement mechanisms, and skill description improvements.","frontmatter":{"title":"Medium-Impact Gaps","description":"Prompt maturity advancement, evaluation loops, self-improvement mechanisms, and skill description improvements."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/05-medium-impact-gaps.md","filePath":"reports/agentic-engineering-techniques/05-medium-impact-gaps.md"}'),o={name:"reports/agentic-engineering-techniques/05-medium-impact-gaps.md"};function l(r,s,p,h,d,c){return i(),t("div",null,[...s[0]||(s[0]=[a('<figure class="report-section-image-wrapper" aria-labelledby="fig-medium-gaps-caption"><img src="'+n+`" alt="A gardener tending to a terraced hillside, each level slightly more cultivated than the one below" loading="lazy" class="report-section-image"><figcaption id="fig-medium-gaps-caption">Cultivating incremental improvements across the maturity levels</figcaption></figure><h2 id="_5-medium-impact-gaps" tabindex="-1">5. Medium-Impact Gaps <a class="header-anchor" href="#_5-medium-impact-gaps" aria-label="Permalink to &quot;5. Medium-Impact Gaps&quot;">​</a></h2><p>These gaps don&#39;t block the workflow but limit its long-term effectiveness and scalability. Each represents an opportunity to move the system from functional to robust.</p><h3 id="gap-g-missing-prompt-model-contract" tabindex="-1">Gap G: Missing prompt-model contract <a class="header-anchor" href="#gap-g-missing-prompt-model-contract" aria-label="Permalink to &quot;Gap G: Missing prompt-model contract&quot;">​</a></h3><p>Skills assume Claude understands WordPress/Laravel tooling, ACF patterns, GDPR requirements, and PHP ecosystem conventions. When these assumptions fail (wrong model, knowledge cutoff, hallucinated tool), there&#39;s no explicit contract to diagnose the problem.</p><p><strong>Recommendation:</strong> Add a <code>## Model Assumptions</code> section to domain-dependent skills:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Model Assumptions</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Model has knowledge of WordPress core APIs, ACF, and common Laravel patterns</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Model can reason about system integration but NOT perform real-time cost lookups</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If a tool or framework is unfamiliar, the model should say so rather than guess</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Model understands UK GDPR requirements at a general level</span></span></code></pre></div><p><strong>Effort:</strong> Low (30 minutes across affected skills)</p><h3 id="gap-h-skill-description-enrichment" tabindex="-1">Gap H: Skill description enrichment <a class="header-anchor" href="#gap-h-skill-description-enrichment" aria-label="Permalink to &quot;Gap H: Skill description enrichment&quot;">​</a></h3><p>The book identifies three elements for reliable model-invoked matching: <strong>trigger terms</strong>, <strong>scope boundaries</strong>, and <strong>differentiation</strong>. Current descriptions are functional but terse.</p><p><strong>Current architect description:</strong></p><blockquote><p>Design technically coherent AI systems for WordPress and Laravel environments.</p></blockquote><p><strong>Improved version:</strong></p><blockquote><p>Design technically coherent AI systems for WordPress and Laravel environments. Use when evaluating system architecture, tool selection, integration feasibility, data flow, or scalability for AI initiatives. NOT for cost analysis (use cost-governor), governance policy (use governance), or business prioritisation (use strategist).</p></blockquote><p>This pattern — positive triggers + negative scope boundaries + routing to alternatives — should be applied across all eight skills.</p><p><strong>Effort:</strong> Low (2 hours total)</p><h3 id="gap-i-no-self-improvement-loop" tabindex="-1">Gap I: No self-improvement loop <a class="header-anchor" href="#gap-i-no-self-improvement-loop" aria-label="Permalink to &quot;Gap I: No self-improvement loop&quot;">​</a></h3><p>The book&#39;s Self-Improving Experts pattern describes agents that update their own instructions based on outcomes. The workflow currently has no feedback mechanism — when a skill produces subpar output, improvement is ad-hoc.</p><p><strong>The book&#39;s approach:</strong></p><ol><li><strong>Execute</strong> — run the skill</li><li><strong>Analyse</strong> — review output quality after the run</li><li><strong>Improve</strong> — extract learnings and update the skill</li></ol><p>The separation between execution and learning is deliberate — it prevents race conditions in multi-agent systems and keeps agents focused during execution.</p><p><strong>Recommendation:</strong> Add a lightweight post-run improvement step. After reconciliation, review each agent&#39;s contribution and capture learnings in a structured log:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Post-Run Improvement Log — [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Date</span><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### architect</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Output quality: Good</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Missing: Did not address CI/CD integration points for this initiative type</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Action: Add CI/CD to the Required Output Structure checklist</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### critic</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Output quality: Fair</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Issue: Over-focused on cost, under-focused on operational risk</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Action: Rebalance focus weights in the &quot;You Focus ONLY On&quot; section</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### governance</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Output quality: Strong</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> No changes needed</span></span></code></pre></div><p>Over time, these logs become the evidence base for skill improvements — replacing intuition with observation.</p><p><strong>Effort:</strong> Low (add template, discipline to fill it)</p><h3 id="gap-j-no-progressive-disclosure-for-reference-material" tabindex="-1">Gap J: No progressive disclosure for reference material <a class="header-anchor" href="#gap-j-no-progressive-disclosure-for-reference-material" aria-label="Permalink to &quot;Gap J: No progressive disclosure for reference material&quot;">​</a></h3><p>The book describes a three-layer architecture for skills: discovery (short metadata), activation (full instructions), and resource (detailed references loaded on demand). The workflow has layers 1 and 2 but no resource layer.</p><p>When a skill needs domain reference material — approved tooling lists, GDPR checklists, WordPress API patterns, client-specific constraints — there&#39;s no mechanism to load these on demand. Either the information is baked into the skill (inflating context) or it&#39;s missing entirely.</p><p><strong>Recommendation:</strong> Create a <code>resources/</code> directory alongside skills:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.cursor/skills/</span></span>
<span class="line"><span>├── architect/</span></span>
<span class="line"><span>│   ├── SKILL.md</span></span>
<span class="line"><span>│   └── resources/</span></span>
<span class="line"><span>│       ├── approved-tooling.md</span></span>
<span class="line"><span>│       └── wp-laravel-integration-patterns.md</span></span>
<span class="line"><span>├── governance/</span></span>
<span class="line"><span>│   ├── SKILL.md</span></span>
<span class="line"><span>│   └── resources/</span></span>
<span class="line"><span>│       ├── gdpr-checklist.md</span></span>
<span class="line"><span>│       └── client-approval-template.md</span></span></code></pre></div><p>Add a <code>## Resources</code> section to skills with guidance on when to load:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Resources</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Load on demand (do not read unless relevant to this initiative):</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \`resources/approved-tooling.md\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — when evaluating tool choices</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \`resources/wp-laravel-integration-patterns.md\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — when designing integrations</span></span></code></pre></div><p><strong>Effort:</strong> Medium (create initial resource files and update skills)</p><h3 id="gap-k-no-agent-debugging-methodology" tabindex="-1">Gap K: No agent debugging methodology <a class="header-anchor" href="#gap-k-no-agent-debugging-methodology" aria-label="Permalink to &quot;Gap K: No agent debugging methodology&quot;">​</a></h3><p>When skill output quality degrades, there&#39;s no documented process for diagnosing the cause. The book describes a systematic approach:</p><ol><li><strong>Classify</strong> — Is this a prompt problem, model problem, context problem, or tool problem?</li><li><strong>Isolate</strong> — Test the prompt with minimal context</li><li><strong>Verbose</strong> — Ask the model to explain its interpretation</li><li><strong>Simplify</strong> — Remove sections until behaviour changes</li><li><strong>Contrast</strong> — Compare working vs failing cases</li></ol><p>Signs of prompt problems vs model limitations:</p><ul><li>Inconsistent behaviour across runs → prompt ambiguity</li><li>Following instructions literally but missing intent → prompt clarity issue</li><li>Correct reasoning, wrong output format → missing examples</li><li>Explaining why it can&#39;t do something it actually can → prompt-model contract violation</li></ul><p><strong>Recommendation:</strong> Document this methodology in the orchestration folder as a reference for when output quality issues arise.</p><p><strong>Effort:</strong> Low (1 hour to document)</p><h3 id="gap-l-distributed-prompt-architecture-—-no-composition-map" tabindex="-1">Gap L: Distributed prompt architecture — no composition map <a class="header-anchor" href="#gap-l-distributed-prompt-architecture-—-no-composition-map" aria-label="Permalink to &quot;Gap L: Distributed prompt architecture — no composition map&quot;">​</a></h3><p>The prompt in agentic systems spans multiple files: skills, rules, injected context, orchestration templates. When output quality degrades, there&#39;s no map showing which files contribute to the agent&#39;s context at each step — making it impossible to isolate which layer is causing the problem.</p><p><strong>Recommendation:</strong> Create a <code>PROMPT_ARCHITECTURE.md</code> in the orchestration folder:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Context Composition by Phase</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### Phase 1: Individual Agent Analysis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Context sources:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Cursor system instructions (implicit)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .cursor/rules/research-output.md (output conventions)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .cursor/skills/{agent}/SKILL.md (role + constraints + output structure)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Initiative intake document (user-provided)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### Phase 2: Reconciliation</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Context sources:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1–4 above, plus:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> All Phase 1 agent outputs (accumulated)</span></span></code></pre></div><p>This map enables the book&#39;s &quot;Isolate&quot; debugging step — you can remove context layers to find which one is causing the problem.</p><p><strong>Effort:</strong> Low (1 hour)</p><h3 id="prompt-maturity-advancement-path" tabindex="-1">Prompt maturity advancement path <a class="header-anchor" href="#prompt-maturity-advancement-path" aria-label="Permalink to &quot;Prompt maturity advancement path&quot;">​</a></h3><p>Where skills sit now and where they could go:</p><table tabindex="0"><thead><tr><th>Current</th><th>Improvement</th><th>Target</th><th>Effort</th></tr></thead><tbody><tr><td>L4: Contextual</td><td>Add orchestration between skills (one-shot runner as Higher-Order)</td><td>L5: Higher-Order</td><td>Medium</td></tr><tr><td>L4: Contextual</td><td>Add post-run improvement logging</td><td>L6: Self-Modifying</td><td>Medium</td></tr><tr><td>L4: Contextual</td><td>Build a meta-skill that audits other skills against the rubric</td><td>L7: Meta-Cognitive</td><td>High</td></tr></tbody></table><p>The book recommends keeping individual skills at Level 4 and elevating the orchestration layer to Level 5. Levels 6–7 are rare and should only be pursued once the evaluation infrastructure is in place to validate that self-modification is actually improving quality.</p>`,50)])])}const m=e(o,[["render",l]]);export{k as __pageData,m as default};
